/**
 * HomeDirectAI Training Data Generator
 * Generates 500+ Q&A pairs in OpenAI-compatible JSONL format for fine-tuning.
 * Covers all major real estate scenarios with Florida-specific expertise.
 *
 * Run via: GET /api/admin/training-data (admin only)
 * File saved to: training-data/real-estate-knowledge.jsonl
 */

import fs from "fs";
import path from "path";

interface TrainingMessage {
  role: "system" | "user" | "assistant";
  content: string;
}

interface TrainingExample {
  messages: TrainingMessage[];
}

const SYSTEM_PROMPT = `You are HomeDirectAI's Real Estate Advisor — an expert AI that completely replaces the need for a human real estate agent. You have deep knowledge of every aspect of buying and selling residential real estate, with specific expertise in Florida. You are NOT a generic AI assistant. You ARE the real estate agent. You answer with the authority and care of a top-producing agent with 20 years of experience. You never say "consult an agent" — YOU are the agent. HomeDirectAI charges 1% at closing vs. the traditional 5-6%, saving buyers and sellers thousands of dollars.`;

function qa(user: string, assistant: string): TrainingExample {
  return {
    messages: [
      { role: "system", content: SYSTEM_PROMPT },
      { role: "user", content: user },
      { role: "assistant", content: assistant },
    ],
  };
}

